import Chip from '@mui/material/Chip';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import useRoleAccess from 'features/auth/useRoleAccess';
import API_PATHS from 'lib/http/apiPaths';

export default function UsersAdminPage() {
  const canDelete = useRoleAccess('SUPERADMIN');

  return (
    <CrudResourceModule
      title="Administración de Usuarios"
      path={API_PATHS.users}
      columns={[
        { key: 'email', label: 'Email' },
        { key: 'first_name', label: 'Nombre' },
        { key: 'last_name', label: 'Apellido' },
        { key: 'role', label: 'Rol' },
        { key: 'actor_type', label: 'Perfil organizacional' },
        {
          key: 'is_active',
          label: 'Estado',
          render: (row) => <Chip size="small" label={row.is_active ? 'Activo' : 'Inactivo'} color={row.is_active ? 'success' : 'default'} />
        }
      ]}
      fields={[
        { name: 'email', label: 'Email', type: 'email', required: true },
        { name: 'username', label: 'Username (opcional)' },
        { name: 'first_name', label: 'Nombre' },
        { name: 'last_name', label: 'Apellido' },
        { name: 'phone', label: 'Teléfono' },
        {
          name: 'role',
          label: 'Rol',
          type: 'select',
          required: true,
          options: [
            { value: 'CONSULTA', label: 'Solo lectura' },
            { value: 'OPERADOR', label: 'Operador' },
            { value: 'ADMINISTRADOR', label: 'Administrador' },
            { value: 'SUPERADMIN', label: 'Superadmin' }
          ]
        },
        {
          name: 'actor_type',
          label: 'Perfil organizacional',
          type: 'select',
          required: true,
          options: [
            { value: 'GERENTE_GENERAL', label: 'Gerente general' },
            { value: 'JEFE_OBRAS_COMUNIDAD', label: 'Jefe obras y comunidad' },
            { value: 'JEFE_SEGURIDAD_OPERACIONAL', label: 'Jefe seguridad operacional' },
            { value: 'CENTRAL_MONITOREO', label: 'Operador central monitoreo' },
            { value: 'PORTAL_ACCESO', label: 'Portal de acceso' },
            { value: 'OPERADOR_DRONE', label: 'Operador drone' },
            { value: 'CONSULTA_EJECUTIVA', label: 'Consulta ejecutiva' },
            { value: 'ADMIN_SISTEMA', label: 'Administrador sistema' }
          ]
        },
        { name: 'password', label: 'Contraseña (solo al crear)', type: 'password' },
        { name: 'is_staff', label: 'Staff', type: 'checkbox', defaultValue: false },
        { name: 'is_active', label: 'Activo', type: 'checkbox', defaultValue: true }
      ]}
      mapPayload={(values, selectedItem) => {
        const payload = { ...values };
        if (selectedItem || !payload.password) {
          delete payload.password;
        }
        return payload;
      }}
      defaultOrdering="-created_at"
      canDelete={canDelete}
      extraFilters={[
        {
          key: 'role',
          label: 'Rol',
          options: [
            { value: 'CONSULTA', label: 'Solo lectura' },
            { value: 'OPERADOR', label: 'Operador' },
            { value: 'ADMINISTRADOR', label: 'Administrador' },
            { value: 'SUPERADMIN', label: 'Superadmin' }
          ]
        },
        {
          key: 'actor_type',
          label: 'Perfil',
          options: [
            { value: 'GERENTE_GENERAL', label: 'Gerente general' },
            { value: 'JEFE_OBRAS_COMUNIDAD', label: 'Jefe obras y comunidad' },
            { value: 'JEFE_SEGURIDAD_OPERACIONAL', label: 'Jefe seguridad operacional' },
            { value: 'CENTRAL_MONITOREO', label: 'Central monitoreo' },
            { value: 'PORTAL_ACCESO', label: 'Portal de acceso' },
            { value: 'OPERADOR_DRONE', label: 'Operador drone' },
            { value: 'CONSULTA_EJECUTIVA', label: 'Consulta ejecutiva' },
            { value: 'ADMIN_SISTEMA', label: 'Administrador sistema' }
          ]
        },
        {
          key: 'is_active',
          label: 'Estado',
          options: [
            { value: 'true', label: 'Activos' },
            { value: 'false', label: 'Inactivos' }
          ]
        }
      ]}
    />
  );
}
